questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Component values ===== */
R_val:  if set=1 then 560  else if set=2 then 3000 else 2000;
L_val:  0.1;
C_val:  if set=1 then 1e-7 else if set=2 then 1e-6 else 1e-7;
C_uF:   float(C_val*1e6);
Vs_val: if set=1 then 100  else if set=2 then 50   else 75;

/* ===== Damping parameters ===== */
ta_alpha:  float(R_val/(2*L_val));
ta_omega0: float(1/sqrt(L_val*C_val));
disc: float(ta_alpha^2 - ta_omega0^2);

/* ===== Regime classification ===== */
/* 1=overdamped, 2=underdamped, 3=critically damped */
ta_regime: if abs(disc) < 0.01 then 3
           else if disc > 0 then 1
           else 2;
regime_name: if ta_regime=1 then "overdamped"
             else if ta_regime=2 then "underdamped"
             else "critically damped";

/* ===== Damped frequency / root separation ===== */
ta_omegad: float(sqrt(abs(disc)));

/* ===== Characteristic roots ===== */
s1_r: if ta_regime=1 then float(-ta_alpha+sqrt(disc)) else float(-ta_alpha);
s2_r: if ta_regime=1 then float(-ta_alpha-sqrt(disc)) else float(-ta_alpha);

/* ===== Initial derivative ===== */
didt0: float(-Vs_val/L_val);

/* ===== Coefficients for i(t) ===== */
ta_A1: if ta_regime=1 then float(didt0/(s1_r-s2_r)) else 0;
ta_A2: if ta_regime=1 then float(-ta_A1) else 0;
ta_B2: if ta_regime=2 then float(didt0/ta_omegad) else 0;
ta_D1: if ta_regime=3 then float(didt0) else 0;

/* ===== Teacher answers ===== */
ta1: [[1, true, "Capacitor = open circuit at DC, so i(0⁻) = 0 A and v_C(0⁻) = Vs"], [2, false, "Inductor = open circuit at DC, so i(0⁻) = 0 and v_C(0⁻) = 0"], [3, false, "Both components block DC, so i = 0 and v_C = 0"], [4, false, "Inductor = short circuit carrying Vs/R, so v_C = 0"]];
ta2: 0;
ta3: float(Vs_val);
ta4: ta_alpha;
ta5: ta_omega0;
ta6: [[1, is(ta_regime=1), "Overdamped"], [2, is(ta_regime=2), "Underdamped"], [3, is(ta_regime=3), "Critically damped"]];

/* Explicit correct values for PRT comparison (MCQ lists fail with AlgEquiv) */
ta1_correct: 1;
ta6_correct: ta_regime;

ta7: if ta_regime=1 then s1_r
     else if ta_regime=2 then (-ta_alpha + ta_omegad*%i)
     else float(-ta_alpha);

ta8: if ta_regime=1 then ta_A1*exp(s1_r*t)+ta_A2*exp(s2_r*t)
     else if ta_regime=2 then ta_B2*exp(-ta_alpha*t)*sin(ta_omegad*t)
     else ta_D1*t*exp(-ta_alpha*t);

/* ===== Pre-computed test-point values for i(t) numerical check ===== */
/* Evaluate ta8 at three test points to verify student expression numerically */
t_test1: 1.0e-4;
t_test2: 5.0e-4;
t_test3: 1.0e-3;
ta8_at_t1: float(subst(t=t_test1, ta8));
ta8_at_t2: float(subst(t=t_test2, ta8));
ta8_at_t3: float(subst(t=t_test3, ta8));

feedbackvariables.text:
/* For numerical fallback: extract real and imaginary parts */
ta7_real: float(realpart(ta7));
ta7_imag: float(imagpart(ta7));
sa7_real: float(realpart(ans7));
sa7_imag: float(imagpart(ans7));
/* Check magnitude of the difference relative to magnitude of ta7 */
err_real: if abs(ta7_real) > 0.01 then abs((sa7_real - ta7_real)/ta7_real) else abs(sa7_real - ta7_real);
err_imag: if abs(ta7_imag) > 0.01 then abs((sa7_imag - ta7_imag)/ta7_imag) else abs(sa7_imag - ta7_imag);
s1_num_ok: if err_real < 0.02 and err_imag < 0.02 then true else false;

/* Evaluate student answer at three test points */
sa8_at_t1: float(subst(t=t_test1, ans8));
sa8_at_t2: float(subst(t=t_test2, ans8));
sa8_at_t3: float(subst(t=t_test3, ans8));

/* Compute relative errors at each test point */
/* Use absolute error if teacher value is near zero */
rerr1: if abs(ta8_at_t1) > 1.0e-10 then abs((sa8_at_t1 - ta8_at_t1)/ta8_at_t1) else abs(sa8_at_t1 - ta8_at_t1);
rerr2: if abs(ta8_at_t2) > 1.0e-10 then abs((sa8_at_t2 - ta8_at_t2)/ta8_at_t2) else abs(sa8_at_t2 - ta8_at_t2);
rerr3: if abs(ta8_at_t3) > 1.0e-10 then abs((sa8_at_t3 - ta8_at_t3)/ta8_at_t3) else abs(sa8_at_t3 - ta8_at_t3);

/* All three test points must agree within 5% */
it_num_ok: if rerr1 < 0.05 and rerr2 < 0.05 and rerr3 < 0.05 then true else false;
